140	njs_inline njs_int_t
141	njs_primitive_value_to_key(njs_vm_t *vm, njs_value_t *dst,
142	    const njs_value_t *src)
143	{
144	    switch (src->type) {
145	    case NJS_NULL:
146	        njs_atom_to_value(vm, dst, NJS_ATOM_STRING_null);
147	        return NJS_OK;
148	
149	    case NJS_UNDEFINED:
150	        njs_atom_to_value(vm, dst, NJS_ATOM_STRING_undefined);
151	        return NJS_OK;
152	
153	    case NJS_BOOLEAN:
154	        if (njs_is_true(src)) {
155	            njs_atom_to_value(vm, dst, NJS_ATOM_STRING_true);
156	
157	        } else {
158	            njs_atom_to_value(vm, dst, NJS_ATOM_STRING_false);
159	        }
160	
161	        return NJS_OK;
162	
163	    case NJS_NUMBER:
164	    case NJS_SYMBOL:
165	    case NJS_STRING:
166	        *dst = *src;
167	        return NJS_OK;
168	
169	    default:
170	        return NJS_ERROR;
171	    }
172	}
