216	njs_key_string_get(njs_vm_t *vm, njs_value_t *key, njs_str_t *str)
217	{
218	    njs_int_t  ret;
219	
220	    if (njs_slow_path(njs_is_symbol(key))) {
221	        ret = njs_symbol_descriptive_string(vm, key, key);
222	        if (njs_slow_path(ret != NJS_OK)) {
223	            return ret;
224	        }
225	
226	    } else if (njs_slow_path(!njs_is_string(key))) {
227	        ret = njs_value_to_string(vm, key, key);
228	        if (njs_slow_path(ret != NJS_OK)) {
229	            return ret;
230	        }
231	    }
232	
233	    njs_string_get(vm, key, str);
234	
235	    return NJS_OK;
236	}
