240	njs_atom_string_get(njs_vm_t *vm, uint32_t atom_id, njs_str_t *str)
241	{
242	    njs_value_t  value;
243	
244	    if (njs_atom_to_value(vm, &value, atom_id) != NJS_OK) {
245	        str->start = (u_char *) "unknown";
246	        str->length = njs_length("unknown");
247	        return;
248	    }
249	
250	    njs_key_string_get(vm, &value, str);
251	}
