255	njs_object_prop_define_val(njs_vm_t *vm, njs_value_t *object, njs_value_t *name,
256	    njs_value_t *value, unsigned flags)
257	{
258	    njs_int_t  ret;
259	
260	    if (njs_value_atom(name) == NJS_ATOM_STRING_unknown) {
261	        ret = njs_atom_atomize_key(vm, name);
262	        if (ret != NJS_OK) {
263	            return ret;
264	        }
265	    }
266	
267	    if (njs_is_string(name)) {
268	       flags |= NJS_OBJECT_PROP_IS_STRING;
269	    }
270	
271	    return njs_object_prop_define(vm, object, name->atom_id, value, flags);
272	}
