308	njs_inline njs_int_t
309	njs_object_string_tag(njs_vm_t *vm, njs_value_t *value, njs_value_t *tag)
310	{
311	    njs_int_t  ret;
312	
313	    ret = njs_value_property(vm, value, NJS_ATOM_SYMBOL_toStringTag, tag);
314	    if (njs_slow_path(ret != NJS_OK)) {
315	        return ret;
316	    }
317	
318	    if (!njs_is_string(tag)) {
319	        return NJS_DECLINED;
320	    }
321	
322	    return NJS_OK;
