326	njs_inline njs_object_t *
327	_njs_object_proto_lookup(njs_object_t *proto, njs_value_type_t type)
328	{
329	    do {
330	        if (njs_fast_path(proto->type == type)) {
331	            break;
332	        }
333	
334	        proto = proto->__proto__;
335	    } while (proto != NULL);
336	
337	    return proto;
338	}
