1088	njs_values_same_non_numeric(njs_vm_t *vm, const njs_value_t *val1,
1089	    const njs_value_t *val2)
1090	{
1091	    if (njs_is_string(val1)) {
1092	        return njs_string_eq(vm, val1, val2);
1093	    }
1094	
1095	    if (njs_is_symbol(val1)) {
1096	        return njs_symbol_eq(val1, val2);
1097	    }
1098	
1099	    return (njs_object(val1) == njs_object(val2));
1100	}
