1103	njs_inline njs_bool_t
1104	njs_values_strict_equal(njs_vm_t *vm, const njs_value_t *val1,
1105	    const njs_value_t *val2)
1106	{
1107	    if (val1->type != val2->type) {
1108	        return 0;
1109	    }
1110	
1111	    if (njs_is_numeric(val1)) {
1112	
1113	        if (njs_is_undefined(val1)) {
1114	            return 1;
1115	        }
1116	
1117	        /* Infinities are handled correctly by comparision. */
1118	        return (njs_number(val1) == njs_number(val2));
1119	    }
1120	
