270	            if (njs_slow_path(prev->type == NJS_WHITEOUT)) {
271	                /* Previously deleted property.  */
272	                prop->atom_id = prev->atom_id;
273	                prop->next_elt = prev->next_elt;
274	                *prev = *prop;
275	            }
276	
277	        } else {
278	
279	            pq.fhq.key_hash = atom_id;
280	            pq.fhq.proto = &njs_object_hash_proto;
281	            pq.fhq.replace = 0;
282	            pq.fhq.pool = vm->mem_pool;
283	
284	            ret = njs_flathsh_unique_insert(njs_object_hash(object), &pq.fhq);
285	            if (njs_slow_path(ret != NJS_OK)) {
286	                njs_internal_error(vm, "flathsh insert failed");
287	                return NJS_ERROR;
288	            }
289	
290	            obj_prop = pq.fhq.value;
291	            obj_prop->enumerable = prop->enumerable;
292	            obj_prop->configurable = prop->configurable;
293	            obj_prop->writable = prop->writable;
294	            obj_prop->type = prop->type;
295	            obj_prop->u.value = prop->u.value;
296	        }
297	
298	        return NJS_OK;
299	    }
300	
301	    /* Updating existing prop. */
302	
303	    prev = pq.fhq.value;
304	
305	    switch (prev->type) {
306	    case NJS_PROPERTY:
307	    case NJS_ACCESSOR:
308	    case NJS_PROPERTY_HANDLER:
309	        break;
310	
311	    case NJS_PROPERTY_REF:
312	    case NJS_PROPERTY_PLACE_REF:
313	        if (prev->type == NJS_PROPERTY_REF
314	            && !njs_is_accessor_descriptor(prop)
315	            && (!set_configurable || prop->configurable)
316	            && (!set_enumerable || prop->enumerable)
317	            && (!set_writable || prop->writable))
318	        {
319	            if (njs_is_valid(njs_prop_value(prop))) {
320	                njs_value_assign(njs_prop_ref(prev), njs_prop_value(prop));
321	            }
322	
323	            return NJS_OK;
324	        }
325	
326	        array = njs_array(object);
327	        length = array->length;
328	
329	        ret = njs_array_convert_to_slow_array(vm, array);
330	        if (njs_slow_path(ret != NJS_OK)) {
331	            return ret;
332	        }
333	
334	        ret = njs_array_length_redefine(vm, object, length, 1);
335	        if (njs_slow_path(ret != NJS_OK)) {
336	            return ret;
337	        }
338	
339	        flags &= ~NJS_OBJECT_PROP_CREATE;
340	
341	        goto again;
342	
343	    case NJS_PROPERTY_TYPED_ARRAY_REF:
344	        if (njs_is_accessor_descriptor(prop)) {
345	            goto exception;
346	        }
347	
348	        if ((set_configurable && prop->configurable)
349	            || (set_enumerable && !prop->enumerable)
350	            || (set_writable && !prop->writable))
351	        {
352	            goto exception;
353	        }
354	
355	        if (njs_is_valid(njs_prop_value(prop))) {
356	            return njs_typed_array_set_value(vm,
357	                                         njs_typed_array(njs_prop_value(prev)),
358	                                         njs_prop_magic32(prev),
359	                                         njs_prop_value(prop));
360	        }
361	
362	        return NJS_OK;
363	
364	    default:
365	        njs_internal_error(vm, "unexpected property type \"%s\" "
366	                           "while defining property",
367	                           njs_prop_type_string(prev->type));
368	
369	        return NJS_ERROR;
370	    }
371	
372	    /* 9.1.6.3 ValidateAndApplyPropertyDescriptor */
373	
374	    if (!prev->configurable) {
375	
376	        if (prop->configurable) {
377	            goto exception;
378	        }
379	
380	        if (set_enumerable && prev->enumerable != prop->enumerable) {
381	            goto exception;
382	        }
383	    }
384	
385	    if (!(set_writable || njs_is_data_descriptor(prop))
386	        && !njs_is_accessor_descriptor(prop))
387	    {
388	        goto done;
389	    }
390	
391	    if (njs_is_data_descriptor(prev)
392	        != (set_writable || njs_is_data_descriptor(prop)))
393	    {
394	        if (!prev->configurable) {
395	            goto exception;
396	        }
397	
398	        /*
399	         * 6.b-c Preserve the existing values of the converted property's
400	         * [[Configurable]] and [[Enumerable]] attributes and set the rest of
401	         * the property's attributes to their default values.
402	         */
403	
404	        if (pq.temp) {
405	            pq.fhq.value = NULL;
406	            prop->configurable = prev->configurable;
407	            prop->enumerable = prev->enumerable;
408	            goto set_prop;
409	        }
410	
411	        if (njs_is_data_descriptor(prev)) {
412	            set_writable = 0;
413	            njs_prop_getter(prev) = NULL;
414	            njs_prop_setter(prev) = NULL;
415	
416	        } else {
417	            prev->writable = 0;
418	
419	            njs_set_undefined(njs_prop_value(prev));
420	        }
421	
422	        prev->type = prop->type;
423	
424	    } else if (njs_is_data_descriptor(prev)
425	               && (set_writable || njs_is_data_descriptor(prop)))
426	    {
427	        if (!prev->configurable && !prev->writable) {
428	            if (prop->writable) {
429	                goto exception;
430	            }
431	
432	            if (njs_is_valid(njs_prop_value(prop))
433	                && prev->type != NJS_PROPERTY_HANDLER
434	                && !njs_values_same(vm, njs_prop_value(prop),
435	                                    njs_prop_value(prev)))
436	            {
437	                goto exception;
438	            }
439	        }
440	
441	    } else {
442	        if (!prev->configurable) {
443	            if (njs_prop_getter(prop) != NJS_PROP_PTR_UNSET
444	                && njs_prop_getter(prop) != njs_prop_getter(prev))
445	            {
446	                goto exception;
447	            }
448	
449	            if (njs_prop_setter(prop) != NJS_PROP_PTR_UNSET
450	                && njs_prop_setter(prop) != njs_prop_setter(prev))
451	            {
452	                goto exception;
453	            }
454	        }
455	    }
456	
457	done:
458	
459	    if (njs_slow_path(njs_is_fast_array(object)
460	                      && pq.fhq.key_hash == NJS_ATOM_STRING_length)
461	                      && (set_writable && !prop->writable))
462	    {
463	        array = njs_array(object);
464	        length = array->length;
465	
466	        ret = njs_array_convert_to_slow_array(vm, array);
467	        if (njs_slow_path(ret != NJS_OK)) {
468	            return ret;
469	        }
470	
471	        ret = njs_array_length_redefine(vm, object, length, 1);
472	        if (njs_slow_path(ret != NJS_OK)) {
473	            return ret;
474	        }
475	
476	        goto again;
477	    }
478	
479	    if (njs_is_accessor_descriptor(prop)) {
480	        prev->type = prop->type;
481	
482	        if (njs_prop_getter(prop) != NJS_PROP_PTR_UNSET) {
483	            njs_prop_getter(prev) = njs_prop_getter(prop);
484	        }
485	
486	        if (njs_prop_setter(prop) != NJS_PROP_PTR_UNSET) {
487	            njs_prop_setter(prev) = njs_prop_setter(prop);
488	        }
489	
490	    } else if (njs_is_valid(njs_prop_value(prop))) {
491	
492	        if (prev->type == NJS_PROPERTY_HANDLER) {
493	            if (prev->writable) {
494	                ret = njs_prop_handler(prev)(vm, prev, atom_id, object,
495	                                             njs_prop_value(prop), &retval);
496	                if (njs_slow_path(ret == NJS_ERROR)) {
497	                    return ret;
498	                }
499	
500	                if (ret == NJS_DECLINED) {
501	                    pq.fhq.value = NULL;
502	                    goto set_prop;
503	                }
504	
505	            } else {
506	
507	                prev->type = prop->type;
508	                njs_value_assign(njs_prop_value(prev), njs_prop_value(prop));
509	            }
510	
511	        } else {
512	
513	            if (njs_slow_path(njs_is_array(object)
514	                              && pq.fhq.key_hash == NJS_ATOM_STRING_length))
515	            {
516	                if (!prev->configurable
517	                    && !prev->writable
518	                    && !njs_values_strict_equal(vm, njs_prop_value(prev),
519	                                                njs_prop_value(prop)))
520	                {
521	                    njs_type_error(vm, "Cannot redefine property: \"length\"");
522	                    return NJS_ERROR;
523	                }
524	
525	                if (set_writable) {
526	                    prev->writable = prop->writable;
527	                }
528	
529	                return njs_array_length_set(vm, object, prev,
530	                                            njs_prop_value(prop));
531	            }
532	
533	            njs_value_assign(njs_prop_value(prev), njs_prop_value(prop));
534	        }
535	    }
536	
537	    /*
538	     * 9. For each field of Desc that is present, set the corresponding
539	     * attribute of the property named P of object O to the value of the field.
540	     */
541	
542	    if (set_writable) {
543	        prev->writable = prop->writable;
544	    }
545	
546	    if (set_enumerable) {
547	        prev->enumerable = prop->enumerable;
548	    }
549	
550	    if (set_configurable) {
551	        prev->configurable = prop->configurable;
552	    }
553	
554	    return NJS_OK;
555	
556	exception:
557	
558	    njs_atom_string_get(vm, atom_id, &pq.fhq.key);
559	    njs_type_error(vm, "Cannot redefine property: \"%V\"", &pq.fhq.key);
560	
561	    return NJS_ERROR;
562	}
