565	njs_int_t
566	njs_prop_private_copy(njs_vm_t *vm, njs_property_query_t *pq,
567	    njs_object_t *proto)
568	{
569	    njs_int_t          ret;
570	    njs_value_t        *value, prop_name;
571	    njs_object_t       *object;
572	    njs_function_t     *function;
573	    njs_object_prop_t  *prop, *shared;
574	
575	    shared = pq->fhq.value;
576	
577	    pq->fhq.replace = 0;
578	    pq->fhq.pool = vm->mem_pool;
579	
580	    ret = njs_flathsh_unique_insert(&proto->hash, &pq->fhq);
581	    if (njs_slow_path(ret != NJS_OK)) {
582	        njs_internal_error(vm, "flathsh insert failed");
583	        return NJS_ERROR;
584	    }
585	
586	    prop = pq->fhq.value;
587	    prop->enumerable = shared->enumerable;
588	    prop->configurable = shared->configurable;
589	    prop->writable = shared->writable;
590	    prop->type = shared->type;
591	    prop->u.value = shared->u.value;
592	
593	    if (njs_is_accessor_descriptor(prop)) {
594	        if (njs_prop_getter(prop) != NULL) {
595	            function = njs_function_copy(vm, njs_prop_getter(prop));
596	            if (njs_slow_path(function == NULL)) {
597	                return NJS_ERROR;
598	            }
599	
600	            njs_prop_getter(prop) = function;
601	
602	            if (njs_prop_setter(prop) != NULL
603	                && function->native && njs_prop_setter(prop)->native
604	                && function->u.native == njs_prop_setter(prop)->u.native)
605	            {
606	                njs_prop_setter(prop) = njs_prop_getter(prop);
607	                return NJS_OK;
608	            }
609	        }
610	
611	        if (njs_prop_setter(prop) != NULL) {
612	            function = njs_function_copy(vm, njs_prop_setter(prop));
613	            if (njs_slow_path(function == NULL)) {
614	                return NJS_ERROR;
615	            }
616	
617	            njs_prop_setter(prop) = function;
618	        }
619	
620	        return NJS_OK;
621	    }
622	
623	    value = njs_prop_value(prop);
624	
625	    switch (value->type) {
626	    case NJS_OBJECT:
627	    case NJS_ARRAY:
628	    case NJS_OBJECT_VALUE:
629	        object = njs_object_value_copy(vm, value);
630	        if (njs_slow_path(object == NULL)) {
631	            return NJS_ERROR;
632	        }
633	
634	        value->data.u.object = object;
635	        return NJS_OK;
636	
637	    case NJS_FUNCTION:
638	        function = njs_function_value_copy(vm, value);
639	        if (njs_slow_path(function == NULL)) {
640	            return NJS_ERROR;
641	        }
642	
643	        ret = njs_atom_to_value(vm, &prop_name, pq->fhq.key_hash);
644	        if (ret != NJS_OK) {
645	            return NJS_ERROR;
646	        }
647	
648	        return njs_function_name_set(vm, function, &prop_name, NULL);
649	
650	    default:
651	        break;
652	    }
653	
654	    return NJS_OK;
655	}
