658	static njs_object_prop_t *
659	njs_descriptor_prop(njs_vm_t *vm, const njs_value_t *desc,
660	    njs_object_prop_t *prop, uint32_t *set_enumerable,
661	    uint32_t *set_configurable, uint32_t *set_writable)
662	{
663	    njs_int_t            ret;
664	    njs_bool_t           data, accessor;
665	    njs_value_t          value;
666	    njs_object_t         *desc_object;
667	    njs_function_t       *getter, *setter;
668	    njs_flathsh_query_t  fhq;
669	
670	    if (!njs_is_object(desc)) {
671	        njs_type_error(vm, "property descriptor must be an object");
672	        return NULL;
673	    }
674	
675	    njs_object_prop_init(prop, NJS_PROPERTY, NJS_OBJECT_PROP_UNSET);
676	    *njs_prop_value(prop) = njs_value_invalid;
677	
678	    *set_enumerable = 0;
679	    *set_configurable = 0;
680	    *set_writable = 0;
681	
682	    data = 0;
683	    accessor = 0;
684	    getter = NJS_PROP_PTR_UNSET;
685	    setter = NJS_PROP_PTR_UNSET;
686	    desc_object = njs_object(desc);
687	
688	    fhq.proto = &njs_object_hash_proto;
689	    fhq.key_hash = NJS_ATOM_STRING_get;
690	
691	    ret = njs_object_property(vm, desc_object, &fhq, &value);
692	    if (njs_slow_path(ret == NJS_ERROR)) {
693	        return NULL;
694	    }
695	
696	    if (ret == NJS_OK) {
697	        if (njs_is_defined(&value) && !njs_is_function(&value)) {
698	            njs_type_error(vm, "Getter must be a function");
699	            return NULL;
700	        }
701	
702	        accessor = 1;
703	        getter = njs_is_function(&value) ? njs_function(&value) : NULL;
704	    }
705	
706	    fhq.key_hash = NJS_ATOM_STRING_set;
707	
708	    ret = njs_object_property(vm, desc_object, &fhq, &value);
709	    if (njs_slow_path(ret == NJS_ERROR)) {
710	        return NULL;
711	    }
712	
713	    if (ret == NJS_OK) {
714	        if (njs_is_defined(&value) && !njs_is_function(&value)) {
715	            njs_type_error(vm, "Setter must be a function");
716	            return NULL;
717	        }
718	
719	        accessor = 1;
720	        setter = njs_is_function(&value) ? njs_function(&value) : NULL;
721	    }
722	
723	    fhq.key_hash = NJS_ATOM_STRING_value;
724	
725	    ret = njs_object_property(vm, desc_object, &fhq, &value);
726	    if (njs_slow_path(ret == NJS_ERROR)) {
727	        return NULL;
728	    }
729	
730	    if (ret == NJS_OK) {
731	        data = 1;
732	        njs_value_assign(njs_prop_value(prop), &value);
733	    }
734	
735	    fhq.key_hash = NJS_ATOM_STRING_writable;
736	
737	    ret = njs_object_property(vm, desc_object, &fhq, &value);
738	    if (njs_slow_path(ret == NJS_ERROR)) {
739	        return NULL;
740	    }
741	
742	    if (ret == NJS_OK) {
743	        data = 1;
744	        prop->writable = njs_is_true(&value);
745	        *set_writable = 1;
746	    }
747	
748	    if (accessor && data) {
749	        njs_type_error(vm, "Cannot both specify accessors "
750	                           "and a value or writable attribute");
751	        return NULL;
752	    }
753	
754	    fhq.key_hash = NJS_ATOM_STRING_enumerable;
755	
756	    ret = njs_object_property(vm, desc_object, &fhq, &value);
757	    if (njs_slow_path(ret == NJS_ERROR)) {
758	        return NULL;
759	    }
760	
761	    if (ret == NJS_OK) {
762	        prop->enumerable = njs_is_true(&value);
763	        *set_enumerable = 1;
764	    }
765	
766	    fhq.key_hash = NJS_ATOM_STRING_configurable;
767	
768	    ret = njs_object_property(vm, desc_object, &fhq, &value);
769	    if (njs_slow_path(ret == NJS_ERROR)) {
770	        return NULL;
771	    }
772	
773	    if (ret == NJS_OK) {
774	        prop->configurable = njs_is_true(&value);
775	        *set_configurable = 1;
776	    }
777	
778	    if (accessor) {
779	        prop->type = NJS_ACCESSOR;
780	        njs_prop_getter(prop) = getter;
781	        njs_prop_setter(prop) = setter;
782	    }
783	
784	    return prop;
785	}
