788	njs_int_t
789	njs_object_prop_descriptor(njs_vm_t *vm, njs_value_t *dest,
790	    njs_value_t *value, njs_value_t *key)
791	{
792	    njs_int_t             ret;
793	    njs_object_t          *desc;
794	    njs_object_prop_t     *pr, *prop;
795	    const njs_value_t     *setval;
796	    njs_flathsh_query_t   fhq;
797	    njs_property_query_t  pq;
798	
799	    njs_property_query_init(&pq, NJS_PROPERTY_QUERY_GET, 1);
800	
801	    if (njs_slow_path(!njs_is_key(key))) {
802	        ret = njs_value_to_key(vm, key, key);
803	        if (njs_slow_path(ret != NJS_OK)) {
804	            return ret;
805	        }
806	    }
807	
808	    ret = njs_property_query_val(vm, &pq, value, key);
809	
810	    switch (ret) {
811	    case NJS_OK:
812	        prop = pq.fhq.value;
813	
814	        switch (prop->type) {
815	        case NJS_PROPERTY:
816	        case NJS_ACCESSOR:
817	            break;
818	
819	        case NJS_PROPERTY_HANDLER:
820	            pq.scratch = *prop;
821	            prop = &pq.scratch;
822	            ret = njs_prop_handler(prop)(vm, prop, key->atom_id, value, NULL,
823	                                         njs_prop_value(prop));
824	            if (njs_slow_path(ret == NJS_ERROR)) {
825	                return ret;
826	            }
827	
828	            break;
829	
830	        default:
831	            njs_type_error(vm, "unexpected property type: %s",
832	                           njs_prop_type_string(prop->type));
833	            return NJS_ERROR;
834	        }
835	
836	        break;
837	
838	    case NJS_DECLINED:
839	        njs_set_undefined(dest);
840	        return NJS_OK;
841	
842	    case NJS_ERROR:
843	    default:
844	        return NJS_ERROR;
845	    }
846	
847	    desc = njs_object_alloc(vm);
848	    if (njs_slow_path(desc == NULL)) {
849	        return NJS_ERROR;
850	    }
851	
852	    fhq.proto = &njs_object_hash_proto;
853	    fhq.replace = 0;
854	    fhq.pool = vm->mem_pool;
855	
856	    if (njs_is_data_descriptor(prop)) {
857	        fhq.key_hash = NJS_ATOM_STRING_value;
858	
859	        ret = njs_flathsh_unique_insert(&desc->hash, &fhq);
860	        if (njs_slow_path(ret != NJS_OK)) {
861	            njs_internal_error(vm, "flathsh insert failed");
862	            return NJS_ERROR;
863	        }
864	
865	        pr = fhq.value;
866	
867	        pr->type = NJS_PROPERTY;
868	        pr->enumerable = 1;
869	        pr->configurable = 1;
870	        pr->writable = 1;
871	        pr->u.value = *(njs_prop_value(prop));
872	
873	        fhq.key_hash = NJS_ATOM_STRING_writable;
874	
875	        setval = (prop->writable == 1) ? &njs_value_true : &njs_value_false;
876	
877	        ret = njs_flathsh_unique_insert(&desc->hash, &fhq);
878	        if (njs_slow_path(ret != NJS_OK)) {
879	            njs_internal_error(vm, "flathsh insert failed");
880	            return NJS_ERROR;
881	        }
882	
883	        pr = fhq.value;
884	
885	        pr->type = NJS_PROPERTY;
886	        pr->enumerable = 1;
887	        pr->configurable = 1;
888	        pr->writable = 1;
889	        pr->u.value = *setval;
890	
891	    } else {
892	
893	        fhq.key_hash = NJS_ATOM_STRING_get;
894	
895	        ret = njs_flathsh_unique_insert(&desc->hash, &fhq);
896	        if (njs_slow_path(ret != NJS_OK)) {
897	            njs_internal_error(vm, "flathsh insert failed");
898	            return NJS_ERROR;
899	        }
900	
901	        pr = fhq.value;
902	
903	        pr->type = NJS_PROPERTY;
904	        pr->enumerable = 1;
905	        pr->configurable = 1;
906	        pr->writable = 1;
907	        pr->u.value = njs_value_undefined;
908	
909	        if (njs_prop_getter(prop) != NULL) {
910	            njs_set_function(njs_prop_value(pr), njs_prop_getter(prop));
911	        }
912	
913	        fhq.key_hash = NJS_ATOM_STRING_set;
914	
915	        ret = njs_flathsh_unique_insert(&desc->hash, &fhq);
916	        if (njs_slow_path(ret != NJS_OK)) {
917	            njs_internal_error(vm, "flathsh insert failed");
918	            return NJS_ERROR;
919	        }
920	
921	        pr = fhq.value;
922	
923	        pr->type = NJS_PROPERTY;
924	        pr->enumerable = 1;
925	        pr->configurable = 1;
926	        pr->writable = 1;
