344	                                    | NJS_ENUM_ENUMERABLE_ONLY);
345	    if (array == NULL) {
346	        return NJS_ERROR;
347	    }
348	
349	    njs_set_array(retval, array);
350	
351	    return NJS_OK;
352	}
