355	static njs_int_t
356	njs_object_entries(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
357	    njs_index_t unused, njs_value_t *retval)
358	{
359	    njs_array_t  *array;
360	    njs_value_t  *value;
361	
362	    value = njs_arg(args, nargs, 1);
363	
364	    if (njs_is_null_or_undefined(value)) {
365	        njs_type_error(vm, "cannot convert %s argument to object",
366	                       njs_type_string(value->type));
367	
368	        return NJS_ERROR;
369	    }
370	
371	    array = njs_value_own_enumerate(vm, value, NJS_ENUM_BOTH | NJS_ENUM_STRING
372	                                    | NJS_ENUM_ENUMERABLE_ONLY);
373	    if (array == NULL) {
374	        return NJS_ERROR;
375	    }
376	
377	    njs_set_array(retval, array);
378	
379	    return NJS_OK;
380	}
