383	static njs_object_prop_t *
384	njs_object_exist_in_proto(const njs_object_t *object, const njs_object_t *end,
385	    njs_flathsh_query_t *fhq)
386	{
387	    njs_int_t          ret;
388	    njs_object_prop_t  *prop;
389	
390	    while (object != end) {
391	        ret = njs_flathsh_unique_find(&object->hash, fhq);
392	
393	        if (njs_fast_path(ret == NJS_OK)) {
394	            prop = fhq->value;
395	
396	            if (prop->type == NJS_WHITEOUT) {
397	                goto next;
398	            }
399	
400	            return fhq->value;
401	        }
402	
403	        ret = njs_flathsh_unique_find(&object->shared_hash, fhq);
404	
405	        if (njs_fast_path(ret == NJS_OK)) {
406	            return fhq->value;
407	        }
408	
409	next:
410	
411	        object = object->__proto__;
412	    }
413	
414	    return NULL;
415	}
