418	njs_inline njs_int_t
419	njs_object_enumerate_value(njs_vm_t *vm, const njs_object_t *object,
420	    njs_array_t *items, uint32_t flags)
421	{
422	    njs_int_t           ret;
423	    njs_object_value_t  *obj_val;
424	
425	    if (flags & NJS_ENUM_STRING) {
426	        switch (object->type) {
427	        case NJS_ARRAY:
428	            ret = njs_object_enumerate_array(vm, (njs_array_t *) object, items,
429	                                             flags);
430	            break;
431	
432	        case NJS_TYPED_ARRAY:
433	            ret = njs_object_enumerate_typed_array(vm,
434	                                                  (njs_typed_array_t *) object,
435	                                                  items, flags);
436	            break;
437	
438	        case NJS_OBJECT_VALUE:
439	            obj_val = (njs_object_value_t *) object;
440	
441	            if (njs_is_string(&obj_val->value)) {
442	                ret = njs_object_enumerate_string(vm, &obj_val->value, items,
443	                                                  flags);
444	                break;
445	            }
446	
447	        /* Fall through. */
448	
449	        default:
450	            goto object;
451	        }
452	
453	        if (njs_slow_path(ret != NJS_OK)) {
454	            return NJS_ERROR;
455	        }
456	    }
457	
458	object:
459	
460	    ret = njs_object_enumerate_object(vm, object, items, flags);
461	    if (njs_slow_path(ret != NJS_OK)) {
462	        return NJS_ERROR;
463	    }
464	
465	    return NJS_OK;
466	}
