569	
570	static njs_int_t
571	njs_object_enumerate_array(njs_vm_t *vm, const njs_array_t *array,
572	    njs_array_t *items, uint32_t flags)
573	{
574	    njs_int_t    ret;
575	    njs_value_t  *p, *start, *end;
576	    njs_array_t  *entry;
577	
578	    if (!array->object.fast_array || array->length == 0) {
579	        return NJS_OK;
580	    }
581	
582	    start = array->start;
583	
584	    p = start;
585	    end = p + array->length;
586	
587	    switch (njs_object_enum_kind(flags)) {
588	    case NJS_ENUM_KEYS:
589	        while (p < end) {
590	            if (njs_is_valid(p)) {
591	                ret = njs_array_expand(vm, items, 0, 1);
592	                if (njs_slow_path(ret != NJS_OK)) {
593	                    return NJS_ERROR;
594	                }
595	
596	                ret = njs_uint32_to_string(vm, &items->start[items->length++],
597	                                           p - start);
598	                if (njs_slow_path(ret != NJS_OK)) {
599	                    return NJS_ERROR;
600	                }
601	            }
602	
603	            p++;
604	        }
605	
606	        break;
607	
608	    case NJS_ENUM_VALUES:
609	        while (p < end) {
610	            if (njs_is_valid(p)) {
611	                ret = njs_array_add(vm, items, p);
612	                if (njs_slow_path(ret != NJS_OK)) {
613	                    return NJS_ERROR;
614	                }
615	            }
616	
617	            p++;
618	        }
619	
620	        break;
621	
622	    case NJS_ENUM_BOTH:
623	        while (p < end) {
624	            if (njs_is_valid(p)) {
625	                entry = njs_array_alloc(vm, 0, 2, 0);
626	                if (njs_slow_path(entry == NULL)) {
627	                    return NJS_ERROR;
628	                }
629	
630	                ret = njs_uint32_to_string(vm, &entry->start[0], p - start);
631	                if (njs_slow_path(ret != NJS_OK)) {
632	                    return NJS_ERROR;
633	                }
634	
635	                entry->start[1] = *p;
636	
637	                ret = njs_array_expand(vm, items, 0, 1);
638	                if (njs_slow_path(ret != NJS_OK)) {
639	                    return NJS_ERROR;
640	                }
641	
642	                njs_set_array(&items->start[items->length++], entry);
643	            }
644	
645	            p++;
646	        }
647	
648	        break;
649	    }
650	
651	    return NJS_OK;
652	}
