654	
655	static njs_int_t
656	njs_object_enumerate_typed_array(njs_vm_t *vm, const njs_typed_array_t *array,
657	    njs_array_t *items, uint32_t flags)
658	{
659	    uint32_t     i, length;
660	    njs_int_t    ret;
661	    njs_value_t  *item;
662	    njs_array_t  *entry;
663	
664	    if (njs_slow_path(njs_is_detached_buffer(array->buffer))) {
665	        njs_type_error(vm, "detached buffer");
666	        return NJS_ERROR;
667	    }
668	
669	    length = njs_typed_array_length(array);
670	
671	    ret = njs_array_expand(vm, items, 0, length);
672	    if (njs_slow_path(ret != NJS_OK)) {
673	        return NJS_ERROR;
674	    }
675	
676	    item = &items->start[items->length];
677	
678	    switch (njs_object_enum_kind(flags)) {
679	    case NJS_ENUM_KEYS:
680	        for (i = 0; i < length; i++) {
681	            ret = njs_uint32_to_string(vm, item++, i);
682	            if (njs_slow_path(ret != NJS_OK)) {
683	                return NJS_ERROR;
684	            }
685	        }
686	
687	        break;
688	
689	    case NJS_ENUM_VALUES:
690	        for (i = 0; i < length; i++) {
691	            njs_set_number(item++, njs_typed_array_prop(array, i));
692	        }
693	
694	        break;
695	
696	    case NJS_ENUM_BOTH:
697	        for (i = 0; i < length; i++) {
698	            entry = njs_array_alloc(vm, 0, 2, 0);
699	            if (njs_slow_path(entry == NULL)) {
700	                return NJS_ERROR;
701	            }
702	
703	            ret = njs_uint32_to_string(vm, &entry->start[0], i);
704	            if (njs_slow_path(ret != NJS_OK)) {
705	                return NJS_ERROR;
706	            }
707	
708	            njs_set_number(&entry->start[1], njs_typed_array_prop(array, i));
709	
710	            njs_set_array(item++, entry);
711	        }
712	
713	        break;
714	    }
715	
716	    items->length += length;
717	
718	    return NJS_OK;
719	}
