721	
722	static njs_int_t
723	njs_object_enumerate_string(njs_vm_t *vm, const njs_value_t *value,
724	    njs_array_t *items, uint32_t flags)
725	{
726	    uint32_t           i, len, size;
727	    njs_int_t          ret;
728	    njs_value_t        *item, *string;
729	    njs_array_t        *entry;
730	    const u_char       *src, *end;
731	    njs_string_prop_t  str_prop;
732	
733	    len = (uint32_t) njs_string_prop(vm, &str_prop, value);
734	
735	    ret = njs_array_expand(vm, items, 0, len);
736	    if (njs_slow_path(ret != NJS_OK)) {
737	        return NJS_ERROR;
738	    }
739	
740	    item = &items->start[items->length];
741	
742	    switch (njs_object_enum_kind(flags)) {
743	    case NJS_ENUM_KEYS:
744	        for (i = 0; i < len; i++) {
745	            ret = njs_uint32_to_string(vm, item++, i);
746	            if (njs_slow_path(ret != NJS_OK)) {
747	                return NJS_ERROR;
748	            }
749	        }
750	
751	        break;
752	
753	    case NJS_ENUM_VALUES:
754	        if (str_prop.size == (size_t) len) {
755	            /* ASCII string. */
756	
757	            for (i = 0; i < len; i++) {
758	                ret = njs_string_new(vm, item, &str_prop.start[i], 1, 1);
759	                if (njs_slow_path(ret != NJS_OK)) {
760	                    return NJS_ERROR;
761	                }
762	
763	                item++;
764	            }
765	
766	        } else {
767	            /* UTF-8 string. */
768	
769	            src = str_prop.start;
770	            end = src + str_prop.size;
771	
772	            do {
773	                size = njs_utf8_next(src, end) - src;
774	
775	                ret = njs_string_new(vm, item, src, size, 1);
776	                if (njs_slow_path(ret != NJS_OK)) {
777	                    return NJS_ERROR;
778	                }
779	
780	                item++;
781	                src += size;
782	
783	            } while (src != end);
784	        }
785	
786	        break;
787	
788	    case NJS_ENUM_BOTH:
789	        if (str_prop.size == (size_t) len) {
790	            /* ASCII string. */
791	
792	            for (i = 0; i < len; i++) {
793	
794	                entry = njs_array_alloc(vm, 0, 2, 0);
795	                if (njs_slow_path(entry == NULL)) {
796	                    return NJS_ERROR;
797	                }
798	
799	                ret = njs_uint32_to_string(vm, &entry->start[0], i);
800	                if (njs_slow_path(ret != NJS_OK)) {
801	                    return NJS_ERROR;
802	                }
803	
804	                string = &entry->start[1];
805	
806	                ret = njs_string_new(vm, string, &str_prop.start[i], 1, 1);
807	                if (njs_slow_path(ret != NJS_OK)) {
808	                    return NJS_ERROR;
809	                }
810	
811	                njs_set_array(item, entry);
812	
813	                item++;
814	            }
815	
816	        } else {
817	            /* UTF-8 string. */
818	
819	            src = str_prop.start;
820	            end = src + str_prop.size;
821	            i = 0;
822	
823	            do {
824	                entry = njs_array_alloc(vm, 0, 2, 0);
825	                if (njs_slow_path(entry == NULL)) {
826	                    return NJS_ERROR;
827	                }
828	
829	                ret = njs_uint32_to_string(vm, &entry->start[0], i++);
830	                if (njs_slow_path(ret != NJS_OK)) {
831	                    return NJS_ERROR;
832	                }
833	
834	                string = &entry->start[1];
835	
836	                size = njs_utf8_next(src, end) - src;
837	
838	                ret = njs_string_new(vm, string, src, size, 1);
839	                if (njs_slow_path(ret != NJS_OK)) {
840	                    return NJS_ERROR;
841	                }
842	
843	                njs_set_array(item, entry);
844	
845	                item++;
846	                src += size;
847	
848	            } while (src != end);
849	        }
850	
851	        break;
852	    }
853	
854	    items->length += len;
855	
856	    return NJS_OK;
857	}
858	
859	
860	static njs_int_t
861	njs_object_enumerate_object(njs_vm_t *vm, const njs_object_t *object,
862	    njs_array_t *items, uint32_t flags)
863	{
864	    njs_int_t           ret;
865	    const njs_object_t  *proto;
866	
867	    ret = njs_object_own_enumerate_object(vm, object, object, items, flags);
868	    if (njs_slow_path(ret != NJS_OK)) {
869	        return NJS_ERROR;
870	    }
871	
872	    proto = object->__proto__;
873	
874	    while (proto != NULL) {
875	        ret = njs_object_own_enumerate_value(vm, proto, object, items, flags);
876	        if (njs_slow_path(ret != NJS_OK)) {
877	            return NJS_ERROR;
878	        }
879	
880	        proto = proto->__proto__;
881	    }
882	
883	    return NJS_OK;
884	}
