887	#define njs_process_prop(vm, prop_name, flags, items, items_symbol)            \
888	    if (!(flags & NJS_ENUM_SYMBOL && njs_is_symbol(prop_name))) {              \
889	        /*                                                                     \
890	         * prop from shared_hash is not symbol:                                \
891	         * add to items before props from hash                                 \
892	         */                                                                    \
893	                                                                               \
894	        ret = njs_array_add(vm, items, prop_name);                             \
895	        if (njs_slow_path(ret != NJS_OK)) {                                    \
896	            return NJS_ERROR;                                                  \
897	        }                                                                      \
898	                                                                               \
899	    } else {                                                                   \
900	        /*                                                                     \
901	         * prop from shared_hash is symbol:                                    \
902	         * add to items_symbol                                                 \
903	         */                                                                    \
904	        ret = njs_array_add(vm, items_symbol, prop_name);                      \
905	        if (njs_slow_path(ret != NJS_OK)) {                                    \
906	            return NJS_ERROR;                                                  \
907	        }                                                                      \
908	    }
