910	
911	static njs_int_t
912	njs_get_own_ordered_keys(njs_vm_t *vm, const njs_object_t *object,
913	    const njs_object_t *parent, njs_array_t *items, uint32_t flags)
914	{
915	    double               num;
916	    uint32_t             items_length;
917	    njs_int_t            ret;
918	    njs_array_t          *items_string, *items_symbol;
919	    njs_value_t          prop_name;
920	    njs_object_prop_t    *prop, *ext_prop;
921	    njs_flathsh_elt_t    *elt;
922	    njs_flathsh_each_t   lhe;
923	    const njs_flathsh_t  *hash;
924	    njs_flathsh_query_t  fhq;
925	
926	    items_length = items->length;
927	
928	    items_string = njs_array_alloc(vm, 1, 0, NJS_ARRAY_SPARE);
929	    if (njs_slow_path(items_string == NULL)) {
930	        return NJS_ERROR;
931	    }
932	
933	    items_symbol = njs_array_alloc(vm, 1, 0, NJS_ARRAY_SPARE);
934	    if (njs_slow_path(items_symbol == NULL)) {
935	        return NJS_ERROR;
936	    }
937	
938	    fhq.proto = &njs_object_hash_proto;
939	
940	    njs_flathsh_each_init(&lhe, &njs_object_hash_proto);
941	    hash = &object->shared_hash;
942	
943	    if (flags & NJS_ENUM_NON_SHARED_ONLY) {
944	        goto local_hash;
945	    }
946	
947	    for ( ;; ) {
948	        elt = njs_flathsh_each(hash, &lhe);
949	        if (elt == NULL) {
950	            break;
951	        }
952	
953	        prop = (njs_object_prop_t *) elt;
954	
955	        ret = njs_atom_to_value(vm, &prop_name, elt->key_hash);
956	        if (ret != NJS_OK) {
957	            return NJS_ERROR;
958	        }
959	
960	        if (!njs_is_enumerable(&prop_name, flags)) {
961	            continue;
962	        }
963	
964	        fhq.key_hash = elt->key_hash;
965	
966	        ext_prop = njs_object_exist_in_proto(parent, object, &fhq);
967	        if (ext_prop != NULL) {
968	            continue;
969	        }
970	
971	        ret = njs_flathsh_unique_find(&object->hash, &fhq);
972	        if (ret != NJS_OK) {
973	
974	            if (!(prop->enumerable || !(flags & NJS_ENUM_ENUMERABLE_ONLY))) {
975	                continue;
976	            }
977	
978	            /* prop is:  !in_hash && in_shared_hash */
979	
980	            num = njs_string_to_index(&prop_name);
981	            if (!njs_number_is_integer_index(num)) {
982	                njs_process_prop(vm, &prop_name, flags, items_string,
983	                                 items_symbol);
984	
985	            } else {
986	                ret = njs_array_add(vm, items, &prop_name);
987	                if (njs_slow_path(ret != NJS_OK)) {
988	                    return NJS_ERROR;
989	                }
990	            }
991	
992	        } else {
993	
994	            if (!(((njs_object_prop_t *) (fhq.value))->enumerable
995	                  || !(flags & NJS_ENUM_ENUMERABLE_ONLY)))
996	            {
997	                continue;
998	            }
999	
1000	            /* prop is:  in_hash && in_shared_hash */
1001	
1002	            num = njs_string_to_index(&prop_name);
1003	            if (!njs_number_is_integer_index(num)) {
1004	
1005	                njs_object_prop_t *hash_prop = fhq.value;
1006	
1007	                if (hash_prop->type != NJS_WHITEOUT) {
1008	                    njs_process_prop(vm, &prop_name, flags, items_string,
1009	                                     items_symbol);
1010	                }
1011	            }
1012	        }
1013	    }
1014	
1015	local_hash:
1016	
1017	    njs_flathsh_each_init(&lhe, &njs_object_hash_proto);
1018	    hash = &object->hash;
1019	
1020	    for ( ;; ) {
1021	        elt = njs_flathsh_each(hash, &lhe);
1022	        if (elt == NULL) {
1023	            break;
1024	        }
1025	
1026	        prop = (njs_object_prop_t *) elt;
1027	
1028	        ret = njs_atom_to_value(vm, &prop_name, elt->key_hash);
1029	        if (ret != NJS_OK) {
1030	            return NJS_ERROR;
1031	        }
1032	
1033	        if (!njs_is_enumerable(&prop_name, flags) ||
1034	            !(prop->enumerable || !(flags & NJS_ENUM_ENUMERABLE_ONLY)) ||
1035	            prop->type == NJS_WHITEOUT)
1036	        {
1037	            continue;
1038	        }
1039	
1040	        fhq.key_hash = elt->key_hash;
1041	
1042	        ext_prop = njs_object_exist_in_proto(parent, object, &fhq);
1043	        if (ext_prop != NULL) {
1044	            continue;
1045	        }
1046	
1047	        num = njs_string_to_index(&prop_name);
1048	        if (njs_number_is_integer_index(num)) {
1049	
1050	            ret = njs_array_add(vm, items, &prop_name);
1051	            if (njs_slow_path(ret != NJS_OK)) {
1052	                return NJS_ERROR;
1053	            }
1054	
1055	        } else {
1056	
1057	            ret = njs_flathsh_unique_find(&object->shared_hash, &fhq);
1058	            if (ret != NJS_OK) {
1059	                /* prop is:  in_hash && !in_shared_hash */
1060	
1061	                /* select names of not deleted props */
1062	                njs_process_prop(vm, &prop_name, flags, items_string,
1063	                                 items_symbol);
1064	
1065	            } else {
1066	                /* prop is:  in_hash && in_shared_hash */
1067	
1068	                if (prop->type == NJS_WHITEOUT) {
1069	                    njs_process_prop(vm, &prop_name, flags, items_string,
1070	                                     items_symbol);
1071	                }
1072	            }
1073	        }
1074	    }
1075	
1076	    if (items->length >= 2) {
1077	        njs_qsort(&items->start[items_length], items->length-items_length,
1078	                  sizeof(njs_value_t), njs_array_indices_handler_nums, NULL);
1079	    }
1080	
1081	    if (items_string->length != 0) {
1082	        ret = njs_array_expand(vm, items, 0, items_string->length);
1083	        if (njs_slow_path(ret != NJS_OK)) {
1084	            return NJS_ERROR;
1085	        }
1086	
1087	        memcpy(&items->start[items->length], &items_string->start[0],
1088	               items_string->length * sizeof(njs_value_t));
1089	
1090	        items->length += items_string->length;
1091	    }
1092	
1093	    if (items_symbol->length != 0) {
1094	        ret = njs_array_expand(vm, items, 0, items_symbol->length);
1095	        if (njs_slow_path(ret != NJS_OK)) {
1096	            return NJS_ERROR;
1097	        }
1098	
1099	        memcpy(&items->start[items->length], &items_symbol->start[0],
1100	               items_symbol->length * sizeof(njs_value_t));
1101	
1102	        items->length += items_symbol->length;
1103	    }
1104	
1105	    njs_array_destroy(vm, items_string);
1106	    njs_array_destroy(vm, items_symbol);
1107	
1108	    return NJS_OK;
1109	}
