1111	
1112	static njs_int_t
1113	njs_object_own_enumerate_object(njs_vm_t *vm, const njs_object_t *object,
1114	    const njs_object_t *parent, njs_array_t *items, uint32_t flags)
1115	{
1116	    uint32_t     i;
1117	    njs_int_t    ret;
1118	    njs_array_t  *items_sorted, *entry;
1119	    njs_value_t  value, retval;
1120	
1121	    switch (njs_object_enum_kind(flags)) {
1122	    case NJS_ENUM_KEYS:
1123	        ret = njs_get_own_ordered_keys(vm, object, parent, items, flags);
1124	        if (ret != NJS_OK) {
1125	            return NJS_ERROR;
1126	        }
1127	
1128	        break;
1129	
1130	    case NJS_ENUM_VALUES:
1131	    case NJS_ENUM_BOTH:
1132	        items_sorted = njs_array_alloc(vm, 1, 0, NJS_ARRAY_SPARE);
1133	        if (njs_slow_path(items_sorted == NULL)) {
1134	            return NJS_ERROR;
1135	        }
1136	
1137	        ret = njs_get_own_ordered_keys(vm, object, parent, items_sorted, flags);
1138	        if (ret != NJS_OK) {
1139	            goto fail;
1140	        }
1141	
1142	        entry = NULL;
1143	        njs_set_object(&value, (njs_object_t *) object);
1144	
1145	        for (i = 0; i< items_sorted->length; i++) {
1146	            ret = njs_value_property_val(vm, &value, &items_sorted->start[i],
1147	                                         &retval);
1148	            if (njs_slow_path(ret != NJS_OK)) {
1149	                njs_array_destroy(vm, items_sorted);
1150	                return NJS_ERROR;
1151	            }
1152	
1153	            if (njs_object_enum_kind(flags) != NJS_ENUM_VALUES) {
1154	                entry = njs_array_alloc(vm, 0, 2, 0);
1155	                if (njs_slow_path(entry == NULL)) {
1156	                    goto fail;
1157	                }
1158	
1159	                njs_string_copy(&entry->start[0], &items_sorted->start[i]);
1160	                njs_value_assign(&entry->start[1], &retval);
1161	
1162	                njs_set_array(&retval, entry);
1163	            }
1164	
1165	            ret = njs_array_add(vm, items, &retval);
1166	            if (njs_slow_path(ret != NJS_OK)) {
1167	                if (njs_object_enum_kind(flags) != NJS_ENUM_VALUES) {
1168	                    njs_array_destroy(vm, entry);
1169	                }
1170	
1171	                goto fail;
1172	            }
1173	        }
1174	
1175	        njs_array_destroy(vm, items_sorted);
1176	
1177	        break;
1178	
1179	    }
1180	
1181	    return NJS_OK;
1182	
1183	fail:
1184	
1185	    njs_array_destroy(vm, items_sorted);
1186	
1187	    return NJS_ERROR;
1188	}
