1191	njs_inline njs_int_t
1192	njs_traverse_visit(njs_arr_t *list, const njs_value_t *value)
1193	{
1194	    njs_object_t  **p;
1195	
1196	    if (njs_is_object(value)) {
1197	        p = njs_arr_add(list);
1198	        if (njs_slow_path(p == NULL)) {
1199	            return NJS_ERROR;
1200	        }
1201	
1202	        *p = njs_object(value);
1203	    }
1204	
1205	    return NJS_OK;
1206	}
