1209	njs_inline njs_int_t
1210	njs_traverse_visited(njs_arr_t *list, const njs_value_t *value)
1211	{
1212	    njs_uint_t    items, n;
1213	    njs_object_t  **start, *obj;
1214	
1215	    if (!njs_is_object(value)) {
1216	        /* External. */
1217	        return 0;
1218	    }
1219	
1220	    start = list->start;
1221	    items = list->items;
1222	    obj = njs_object(value);
1223	
1224	    for (n = 0; n < items; n++) {
1225	        if (start[n] == obj) {
1226	            return 1;
1227	        }
1228	    }
1229	
1230	    return 0;
1231	}
