1234	static njs_int_t
1235	njs_object_copy_shared_hash(njs_vm_t *vm, njs_object_t *object)
1236	{
1237	    njs_int_t            ret;
1238	    njs_value_t          prop_name;
1239	    njs_flathsh_t        new_hash, *shared_hash;
1240	    njs_object_prop_t    *prop, *obj_prop;
1241	    njs_flathsh_elt_t    *elt;
1242	    njs_flathsh_each_t   fhe;
1243	    njs_flathsh_query_t  fhq;
1244	
1245	    fhq.replace = 0;
1246	    fhq.proto = &njs_object_hash_proto;
1247	    fhq.pool = vm->mem_pool;
1248	
1249	    njs_flathsh_init(&new_hash);
1250	    shared_hash = &object->shared_hash;
1251	
1252	    njs_flathsh_each_init(&fhe, &njs_object_hash_proto);
1253	
1254	    for ( ;; ) {
1255	        elt = njs_flathsh_each(shared_hash, &fhe);
1256	        if (elt == NULL) {
1257	            break;
1258	        }
1259	
1260	        prop = (njs_object_prop_t *) elt;
1261	
1262	        ret = njs_atom_to_value(vm, &prop_name, elt->key_hash);
1263	        if (ret != NJS_OK) {
1264	            return NJS_ERROR;
1265	        }
1266	
1267	        if (njs_is_symbol(&prop_name)) {
1268	            fhq.key_hash = njs_symbol_key(&prop_name);
1269	            fhq.key.start = NULL;
1270	
1271	        } else {
1272	            njs_string_get(vm, &prop_name, &fhq.key);
1273	            fhq.key_hash = elt->key_hash;
1274	        }
1275	
1276	        ret = njs_flathsh_unique_insert(&new_hash, &fhq);
1277	        if (njs_slow_path(ret != NJS_OK)) {
1278	            njs_internal_error(vm, "flathsh insert failed");
1279	            return NJS_ERROR;
1280	        }
1281	
1282	        obj_prop = fhq.value;
1283	
1284	        obj_prop->type = prop->type;
1285	        obj_prop->enumerable = prop->enumerable;
1286	        obj_prop->configurable = prop->configurable;
1287	        obj_prop->writable = prop->writable;
1288	        obj_prop->u.value = prop->u.value;
1289	    }
1290	
1291	    object->shared_hash = new_hash;
1292	
1293	    return NJS_OK;
1294	}
