1297	njs_int_t
1298	njs_object_make_shared(njs_vm_t *vm, njs_object_t *object)
1299	{
1300	    njs_int_t             ret;
1301	    njs_arr_t             visited;
1302	    njs_object_t          **start;
1303	    njs_value_t           value, *key;
1304	    njs_traverse_t        *s;
1305	    njs_object_prop_t     *prop, *obj_prop;
1306	    njs_property_query_t  pq;
1307	    njs_traverse_t        state[NJS_TRAVERSE_MAX_DEPTH];
1308	
1309	    s = &state[0];
1310	    s->parent = NULL;
1311	    s->index = 0;
1312	    njs_set_object(&s->value, object);
1313	
1314	    s->keys = njs_value_own_enumerate(vm, &s->value, NJS_ENUM_KEYS
1315	                                      | NJS_ENUM_STRING
1316	                                      | NJS_ENUM_NON_SHARED_ONLY);
1317	    if (njs_slow_path(s->keys == NULL)) {
1318	        return NJS_ERROR;
1319	    }
1320	
1321	    if (s->keys->length != 0
1322	        && !njs_flathsh_is_empty(&object->shared_hash))
1323	    {
1324	        /*
1325	         * object->shared_hash can be shared with other objects
1326	         * and we do not want to modify other objects.
1327	         */
1328	
1329	        ret = njs_object_copy_shared_hash(vm, object);
1330	        if (njs_slow_path(ret != NJS_OK)) {
1331	            return NJS_ERROR;
1332	        }
1333	    }
1334	
1335	    start = njs_arr_init(vm->mem_pool, &visited, NULL, 8, sizeof(void *));
1336	    if (njs_slow_path(start == NULL)) {
1337	        return NJS_ERROR;
1338	    }
1339	
1340	    (void) njs_traverse_visit(&visited, &s->value);
1341	
1342	    pq.fhq.replace = 0;
1343	    pq.fhq.pool = vm->mem_pool;
1344	
1345	    for ( ;; ) {
1346	
1347	        if (s->index >= s->keys->length) {
1348	            njs_flathsh_init(&njs_object(&s->value)->hash);
1349	            njs_object(&s->value)->shared = 1;
1350	            njs_array_destroy(vm, s->keys);
1351	            s->keys = NULL;
1352	
1353	            if (s == &state[0]) {
1354	                goto done;
1355	            }
1356	
1357	            s--;
1358	            continue;
1359	        }
1360	
1361	
1362	        njs_property_query_init(&pq, NJS_PROPERTY_QUERY_GET, 0);
1363	        key = &s->keys->start[s->index++];
1364	
1365	        ret = njs_property_query_val(vm, &pq, &s->value, key);
1366	        if (njs_slow_path(ret != NJS_OK)) {
1367	            if (ret == NJS_DECLINED) {
1368	                continue;
1369	            }
1370	
1371	            return NJS_ERROR;
1372	        }
1373	
1374	
1375	        prop = pq.fhq.value;
1376	
1377	        ret = njs_flathsh_unique_insert(&njs_object(&s->value)->shared_hash,
1378	                                        &pq.fhq);
1379	        if (njs_slow_path(ret != NJS_OK)) {
1380	            njs_internal_error(vm, "flathsh insert failed");
1381	            return NJS_ERROR;
1382	        }
1383	
1384	        obj_prop = pq.fhq.value;
1385	
1386	        obj_prop->type = prop->type;
1387	        obj_prop->enumerable = prop->enumerable;
1388	        obj_prop->configurable = prop->configurable;
1389	        obj_prop->writable = prop->writable;
1390	        obj_prop->u.value = prop->u.value;
1391	
1392	        njs_value_assign(&value, njs_prop_value(prop));
1393	
1394	        if (njs_is_object(&value)
1395	            && !njs_object(&value)->shared
1396	            && !njs_traverse_visited(&visited, &value))
1397	        {
1398	            ret = njs_traverse_visit(&visited, &value);
1399	            if (njs_slow_path(ret != NJS_OK)) {
1400	                return NJS_ERROR;
1401	            }
1402	
1403	            if (s == &state[NJS_TRAVERSE_MAX_DEPTH - 1]) {
1404	                njs_type_error(vm, "njs_object_traverse() recursion limit:%d",
1405	                               NJS_TRAVERSE_MAX_DEPTH);
1406	                return NJS_ERROR;
1407	            }
1408	
1409	            s++;
1410	            s->prop = NULL;
1411	            s->parent = &s[-1];
1412	            s->index = 0;
1413	            njs_value_assign(&s->value, &value);
1414	            s->keys = njs_value_own_enumerate(vm, &s->value, NJS_ENUM_KEYS
1415	                                           | NJS_ENUM_STRING
1416	                                           | NJS_ENUM_NON_SHARED_ONLY);
1417	            if (njs_slow_path(s->keys == NULL)) {
1418	                return NJS_ERROR;
1419	            }
1420	
1421	            if (s->keys->length != 0
1422	                && !njs_flathsh_is_empty(&njs_object(&s->value)->shared_hash))
1423	            {
1424	                ret = njs_object_copy_shared_hash(vm, njs_object(&s->value));
1425	                if (njs_slow_path(ret != NJS_OK)) {
1426	                    return NJS_ERROR;
1427	                }
1428	            }
1429	        }
1430	    }
1431	
1432	done:
1433	
1434	    njs_arr_destroy(&visited);
1435	
1436	    return NJS_OK;
1437	}
