1440	njs_int_t
1441	njs_object_traverse(njs_vm_t *vm, njs_object_t *object, void *ctx,
1442	    njs_object_traverse_cb_t cb)
1443	{
1444	    njs_int_t             ret;
1445	    njs_arr_t             visited;
1446	    njs_object_t          **start;
1447	    njs_value_t           value, *key;
1448	    njs_traverse_t        *s;
1449	    njs_object_prop_t     *prop;
1450	    njs_property_query_t  pq;
1451	    njs_traverse_t        state[NJS_TRAVERSE_MAX_DEPTH];
1452	
1453	    s = &state[0];
1454	    s->prop = NULL;
1455	    s->parent = NULL;
1456	    s->index = 0;
1457	    njs_set_object(&s->value, object);
1458	    s->keys = njs_value_own_enumerate(vm, &s->value, NJS_ENUM_KEYS
1459	                                      | NJS_ENUM_STRING | NJS_ENUM_SYMBOL);
1460	    if (njs_slow_path(s->keys == NULL)) {
1461	        return NJS_ERROR;
1462	    }
1463	
1464	    start = njs_arr_init(vm->mem_pool, &visited, NULL, 8, sizeof(void *));
1465	    if (njs_slow_path(start == NULL)) {
1466	        return NJS_ERROR;
1467	    }
1468	
1469	    (void) njs_traverse_visit(&visited, &s->value);
1470	
1471	    for ( ;; ) {
1472	
1473	        if (s->index >= s->keys->length) {
1474	            njs_array_destroy(vm, s->keys);
1475	            s->keys = NULL;
1476	
1477	            if (s == &state[0]) {
1478	                goto done;
1479	            }
1480	
1481	            s--;
1482	            continue;
1483	        }
1484	
1485	        njs_property_query_init(&pq, NJS_PROPERTY_QUERY_GET, 0);
1486	        key = &s->keys->start[s->index++];
1487	
1488	        ret = njs_property_query_val(vm, &pq, &s->value, key);
1489	        if (njs_slow_path(ret != NJS_OK)) {
1490	            if (ret == NJS_DECLINED) {
1491	                continue;
1492	            }
1493	
1494	            return NJS_ERROR;
1495	        }
1496	
1497	        prop = pq.fhq.value;
1498	        s->prop = prop;
1499	        s->atom_id = pq.fhq.key_hash;
1500	
1501	        ret = cb(vm, s, ctx);
1502	        if (njs_slow_path(ret != NJS_OK)) {
1503	            return ret;
1504	        }
1505	
1506	        if (njs_is_accessor_descriptor(prop)) {
1507	            continue;
1508	        }
1509	
1510	        njs_value_assign(&value, njs_prop_value(prop));
1511	
1512	        if (prop->type == NJS_PROPERTY_HANDLER) {
1513	            ret = njs_prop_handler(prop)(vm, prop, pq.fhq.key_hash, &s->value,
1514	                                         NULL, &value);
1515	            if (njs_slow_path(ret == NJS_ERROR)) {
1516	                return ret;
1517	
1518	            }
1519	        }
1520	
1521	        if (njs_is_object(&value)
1522	            && !njs_traverse_visited(&visited, &value))
1523	        {
1524	            ret = njs_traverse_visit(&visited, &value);
1525	            if (njs_slow_path(ret != NJS_OK)) {
1526	                return NJS_ERROR;
1527	            }
1528	
1529	            if (s == &state[NJS_TRAVERSE_MAX_DEPTH - 1]) {
1530	                njs_type_error(vm, "njs_object_traverse() recursion limit:%d",
1531	                               NJS_TRAVERSE_MAX_DEPTH);
1532	                return NJS_ERROR;
1533	            }
1534	
1535	            s++;
1536	            s->prop = NULL;
1537	            s->parent = &s[-1];
1538	            s->index = 0;
1539	            njs_value_assign(&s->value, &value);
1540	            s->keys = njs_value_own_enumerate(vm, &s->value, NJS_ENUM_KEYS
1541	                                           | NJS_ENUM_STRING | NJS_ENUM_SYMBOL);
1542	            if (njs_slow_path(s->keys == NULL)) {
1543	                return NJS_ERROR;
1544	            }
1545	        }
1546	    }
1547	
1548	done:
1549	
1550	    njs_arr_destroy(&visited);
1551	
1552	    return NJS_OK;
1553	}
