1557	njs_object_define_property(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
1558	    njs_index_t unused, njs_value_t *retval)
1559	{
1560	    njs_int_t    ret;
1561	    njs_value_t  *value, *name, *desc, lvalue;
1562	
1563	    if (!njs_is_object(njs_arg(args, nargs, 1))) {
1564	        njs_type_error(vm, "Object.defineProperty is called on non-object");
1565	        return NJS_ERROR;
1566	    }
1567	
1568	    desc = njs_arg(args, nargs, 3);
1569	
1570	    if (!njs_is_object(desc)) {
1571	        njs_type_error(vm, "descriptor is not an object");
1572	        return NJS_ERROR;
1573	    }
1574	
1575	    value = njs_argument(args, 1);
1576	    name = njs_lvalue_arg(&lvalue, args, nargs, 2);
1577	
1578	    ret = njs_value_to_key(vm, name, name);
1579	    if (njs_slow_path(ret != NJS_OK)) {
1580	        return NJS_ERROR;
1581	    }
1582	
1583	    ret = njs_object_prop_define_val(vm, value, name, desc,
1584	                                     NJS_OBJECT_PROP_DESCRIPTOR);
1585	    if (njs_slow_path(ret != NJS_OK)) {
1586	        return NJS_ERROR;
1587	    }
1588	
1589	    njs_value_assign(retval, value);
1590	
1591	    return NJS_OK;
1592	}
