1595	static njs_int_t
1596	njs_object_define_properties(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
1597	    njs_index_t unused, njs_value_t *retval)
1598	{
1599	    uint32_t              i, length;
1600	    njs_int_t             ret;
1601	    njs_array_t           *keys;
1602	    njs_value_t           desc, *value, *descs;
1603	    njs_object_prop_t     *prop;
1604	    njs_property_query_t  pq;
1605	
1606	    if (!njs_is_object(njs_arg(args, nargs, 1))) {
1607	        njs_type_error(vm, "Object.defineProperties is called on non-object");
1608	        return NJS_ERROR;
1609	    }
1610	
1611	    descs = njs_arg(args, nargs, 2);
1612	    ret = njs_value_to_object(vm, descs);
1613	    if (njs_slow_path(ret != NJS_OK)) {
