2308	njs_object_set_prototype(njs_vm_t *vm, njs_object_t *object,
2309	    const njs_value_t *value)
2310	{
2311	    const njs_object_t *proto;
2312	
2313	    proto = njs_object(value);
2314	
2315	    if (njs_slow_path(object->__proto__ == proto)) {
2316	        return NJS_OK;
2317	    }
2318	
2319	    if (!object->extensible) {
2320	        return NJS_DECLINED;
2321	    }
2322	
