2385	/*
2386	 * The "constructor" property of Object(), Array() and other functions
2387	 * prototypes is created on demand in the prototypes' private hash by the
2388	 * "constructor" getter.  The properties are set to appropriate function.
2389	 */
2390	
2391	njs_int_t
2392	njs_object_prototype_create_constructor(njs_vm_t *vm, njs_object_prop_t *prop,
2393	    uint32_t unused, njs_value_t *value, njs_value_t *setval,
2394	    njs_value_t *retval)
2395	{
2396	    int64_t                 index;
2397	    njs_value_t             *cons, constructor;
2398	    njs_object_t            *object;
2399	    njs_object_prototype_t  *prototype;
2400	
2401	    if (setval != NULL) {
2402	        if (!njs_is_object(value)) {
2403	            njs_type_error(vm, "Cannot create property \"constructor\" on %s",
2404	                           njs_type_string(value->type));
2405	            return NJS_ERROR;
2406	        }
2407	
2408	        cons = njs_property_constructor_set(vm, njs_object_hash(value), setval);
2409	        if (njs_slow_path(cons == NULL)) {
2410	            return NJS_ERROR;
2411	        }
2412	
2413	        *retval = *cons;
2414	        return NJS_OK;
2415	    }
2416	
2417	    if (njs_is_object(value)) {
2418	        object = njs_object(value);
2419	
2420	        do {
2421	            prototype = (njs_object_prototype_t *) object;
2422	            index = prototype - vm->prototypes;
2423	
2424	            if (index >= 0 && (size_t) index < vm->constructors_size) {
2425	                goto found;
2426	            }
2427	
2428	            object = object->__proto__;
2429	
2430	        } while (object != NULL);
2431	
2432	        njs_internal_error(vm, "prototype not found");
2433	
2434	        return NJS_ERROR;
2435	
2436	    } else {
2437	        index = njs_primitive_prototype_index(value->type);
2438	        prototype = &vm->prototypes[index];
2439	    }
2440	
2441	found:
2442	
2443	    if (njs_flathsh_is_empty(&vm->constructors[index].object.shared_hash)) {
2444	        index = NJS_OBJ_TYPE_OBJECT;
2445	    }
2446	
2447	    njs_set_function(&constructor, &njs_vm_ctor(vm, index));
2448	    setval = &constructor;
2449	
2450	    cons = njs_property_constructor_set(vm, &prototype->object.hash, setval);
2451	    if (njs_slow_path(cons == NULL)) {
2452	        return NJS_ERROR;
2453	    }
2454	
2455	    *retval = *cons;
2456	    return NJS_OK;
2457	}
